#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *indeg = (int*)calloc(N+1, sizeof(int));
        for(int i=1;i<=N;i++){
            int r; scanf("%d", &r);
            if(r!=0) indeg[r]++;
        }
        int first=1;
        for(int i=1;i<=N;i++) if(indeg[i]==0){
            if(!first) printf(" ");
            printf("%d", i);
            first=0;
        }
        printf("\n");
        free(indeg);
    }
    return 0;
}

