#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        indeg = [0] * (N + 1)
        for i in range(1, N + 1):
            r = int(next(it))
            if r != 0:
                indeg[r] += 1
        leaves = [str(i) for i in range(1, N + 1) if indeg[i] == 0]
        out_lines.append(' '.join(leaves))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

