  const N = data[idx++];
  const indeg = new Array(N + 1).fill(0);
  for (let i = 1; i <= N; i++) {
    const r = data[idx++];
    if (r !== 0) indeg[r]++;
  }
  const res = [];
  for (let i = 1; i <= N; i++) {
    if (indeg[i] === 0) res.push(i);
  }
  outputs.push(res.join(' '));
}
